# Decorator for OAuth 2.0 protection
def require_oauth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')

        if not auth_header:
            return jsonify({'message': 'Authorization header missing'}), 401

        if not auth_header.startswith('Bearer '):
            return jsonify({'message': 'Invalid Authorization header format'}), 401

        token_string = auth_header.split(' ')[1]

        if not token_string:
            return jsonify({'message': 'Access token missing'}), 401

        access_token = AccessToken.query.filter_by(token=token_string).first()

        if not access_token:
            return jsonify({'message': 'Invalid access token'}), 401

        if not access_token.is_valid:
            # Optionally update the token as revoked/expired in DB for clarity
            if access_token.expires_at <= datetime.utcnow() and not access_token.is_revoked:
                access_token.is_revoked = True
                db.session.commit()
            return jsonify({'message': 'Access token is expired or revoked'}), 401

        # Store the access token object in Flask's global context `g`
        # for downstream access in the API endpoint if needed.
        g.access_token = access_token
        g.user_id = access_token.user_id
        g.client_id = access_token.client_id

        return f(*args, **kwargs)
    return decorated_function

